/**
 * Theme utility functions for theme preference persistence and OS detection
 */

export type ThemeMode = 'dark' | 'light' | 'system';

/**
 * Get the system theme preference from the OS
 */
export function getSystemTheme(): 'dark' | 'light' {
  if (typeof window === 'undefined') return 'dark';
  return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
}

/**
 * Resolve a theme mode to its actual applied theme
 * If mode is 'system', returns the OS preference
 * Otherwise returns the mode itself
 */
export function resolveTheme(mode: ThemeMode): 'dark' | 'light' {
  if (mode === 'system') return getSystemTheme();
  return mode;
}

/**
 * Persist theme preference to localStorage
 */
export function persistThemePreference(mode: ThemeMode): void {
  if (typeof window === 'undefined') return;
  try {
    localStorage.setItem('audira-theme', JSON.stringify({ mode }));
  } catch (e) {
    console.warn('Failed to persist theme preference:', e);
  }
}

/**
 * Read theme preference from localStorage
 */
export function readThemePreference(): ThemeMode | null {
  if (typeof window === 'undefined') return null;
  try {
    const stored = localStorage.getItem('audira-theme');
    if (!stored) return null;
    const parsed = JSON.parse(stored);
    if (parsed.mode && ['dark', 'light', 'system'].includes(parsed.mode)) {
      return parsed.mode;
    }
    return null;
  } catch (e) {
    console.warn('Failed to read theme preference:', e);
    return null;
  }
}

/**
 * Color token definitions for both dark and light modes
 * Format: { dark: { token: '#hex' }, light: { token: '#hex' } }
 */
export const colorTokens = {
  dark: {
    'text-primary': '#ffffff',
    'text-secondary': '#a0a0a0',
    'bg-primary': '#0a0a0a',
    'bg-secondary': '#1a1a1a',
    'bg-tertiary': '#2a2a2a',
    'border-primary': '#3a3a3a',
    'accent-success': '#10b981',
    'accent-error': '#ef4444',
    'accent-warning': '#f59e0b',
    'accent-info': '#3b82f6',
  },
  light: {
    'text-primary': '#000000',
    'text-secondary': '#606060',
    'bg-primary': '#ffffff',
    'bg-secondary': '#f5f5f5',
    'bg-tertiary': '#eeeeee',
    'border-primary': '#e0e0e0',
    'accent-success': '#059669',
    'accent-error': '#dc2626',
    'accent-warning': '#d97706',
    'accent-info': '#2563eb',
  },
};

/**
 * Convert hex color to RGB
 */
function hexToRgb(hex: string): { r: number; g: number; b: number } | null {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result
    ? {
        r: parseInt(result[1], 16),
        g: parseInt(result[2], 16),
        b: parseInt(result[3], 16),
      }
    : null;
}

/**
 * Calculate relative luminance of a color (WCAG formula)
 */
function getLuminance(rgb: { r: number; g: number; b: number }): number {
  const [r, g, b] = [rgb.r, rgb.g, rgb.b].map((val) => {
    const v = val / 255;
    return v <= 0.03928 ? v / 12.92 : Math.pow((v + 0.055) / 1.055, 2.4);
  });
  return 0.2126 * r + 0.7152 * g + 0.0722 * b;
}

/**
 * Calculate WCAG contrast ratio between two colors
 * Returns a number >= 1, where 4.5 is the minimum for AA compliance
 */
export function getContrastRatio(color1: string, color2: string): number {
  const rgb1 = hexToRgb(color1);
  const rgb2 = hexToRgb(color2);

  if (!rgb1 || !rgb2) return 0;

  const lum1 = getLuminance(rgb1);
  const lum2 = getLuminance(rgb2);

  const lighter = Math.max(lum1, lum2);
  const darker = Math.min(lum1, lum2);

  return (lighter + 0.05) / (darker + 0.05);
}

/**
 * Validate that all text/background color pairs meet minimum contrast ratio
 */
export function validateColorContrast(
  mode: 'dark' | 'light',
  minRatio: number = 4.5
): { valid: boolean; failures: Array<{ pair: string; ratio: number }> } {
  const tokens = colorTokens[mode];
  const textTokens = Object.entries(tokens).filter(([key]) => key.startsWith('text-'));
  const bgTokens = Object.entries(tokens).filter(([key]) => key.startsWith('bg-'));

  const failures: Array<{ pair: string; ratio: number }> = [];

  for (const [textKey, textColor] of textTokens) {
    for (const [bgKey, bgColor] of bgTokens) {
      const ratio = getContrastRatio(textColor, bgColor);
      if (ratio < minRatio) {
        failures.push({
          pair: `${textKey} on ${bgKey}`,
          ratio,
        });
      }
    }
  }

  return {
    valid: failures.length === 0,
    failures,
  };
}

/**
 * Notification utility functions for toast management and visual mapping
 */

export type ToastType = 'success' | 'error' | 'warning' | 'info';

export interface Toast {
  id: string;
  type: ToastType;
  title: string;
  message?: string;
  duration?: number;
  dismissible?: boolean;
}

/**
 * Visual mapping for toast types to colors and icons
 */
export interface ToastVisualMapping {
  color: string;
  icon: string;
  bgColor: string;
  borderColor: string;
}

/**
 * Get visual mapping for a toast type
 * Returns color scheme and icon name for the given toast type
 */
export function getToastVisualMapping(type: ToastType): ToastVisualMapping {
  const mappings: Record<ToastType, ToastVisualMapping> = {
    success: {
      color: '#10b981',
      icon: 'check-circle',
      bgColor: '#ecfdf5',
      borderColor: '#d1fae5',
    },
    error: {
      color: '#ef4444',
      icon: 'alert-circle',
      bgColor: '#fef2f2',
      borderColor: '#fee2e2',
    },
    warning: {
      color: '#f59e0b',
      icon: 'alert-triangle',
      bgColor: '#fffbeb',
      borderColor: '#fef3c7',
    },
    info: {
      color: '#3b82f6',
      icon: 'info',
      bgColor: '#eff6ff',
      borderColor: '#dbeafe',
    },
  };

  return mappings[type];
}

/**
 * Toast queue management - enforces max 3 visible toasts
 */
export interface ToastQueueState {
  visible: Toast[];
  queued: Toast[];
}

/**
 * Add a toast to the queue, respecting max visible constraint
 */
export function addToastToQueue(
  state: ToastQueueState,
  toast: Toast,
  maxVisible: number = 3
): ToastQueueState {
  if (state.visible.length < maxVisible) {
    return {
      visible: [...state.visible, toast],
      queued: state.queued,
    };
  }
  return {
    visible: state.visible,
    queued: [...state.queued, toast],
  };
}

/**
 * Remove a toast from visible or queued state
 * Promotes next queued toast if space available
 */
export function removeToastFromQueue(
  state: ToastQueueState,
  toastId: string,
  maxVisible: number = 3
): ToastQueueState {
  const filteredVisible = state.visible.filter((t) => t.id !== toastId);

  // Promote from queue if there's space
  if (state.queued.length > 0 && filteredVisible.length < maxVisible) {
    const [promoted, ...remainingQueue] = state.queued;
    return {
      visible: [...filteredVisible, promoted],
      queued: remainingQueue,
    };
  }

  return {
    visible: filteredVisible,
    queued: state.queued,
  };
}

/**
 * Get the current visible toast count
 */
export function getVisibleToastCount(state: ToastQueueState): number {
  return state.visible.length;
}

/**
 * Get the current queued toast count
 */
export function getQueuedToastCount(state: ToastQueueState): number {
  return state.queued.length;
}

/**
 * Check if a toast is visible
 */
export function isToastVisible(state: ToastQueueState, toastId: string): boolean {
  return state.visible.some((t) => t.id === toastId);
}

/**
 * Get all toasts (visible + queued)
 */
export function getAllToasts(state: ToastQueueState): Toast[] {
  return [...state.visible, ...state.queued];
}

/**
 * Validate toast queue constraints
 * Returns true if queue respects max visible constraint
 */
export function validateToastQueue(
  state: ToastQueueState,
  maxVisible: number = 3
): boolean {
  return state.visible.length <= maxVisible;
}

/**
 * Get toast type from a toast object
 */
export function getToastType(toast: Toast): ToastType {
  return toast.type;
}

/**
 * Milestone detection for celebrations
 */
export type CelebrationMilestone = 'first_100_messages' | 'first_resolved' | 'first_workflow';

export interface CelebrationEvent {
  id: string;
  type: CelebrationMilestone;
  title: string;
  description: string;
}

/**
 * Check if a milestone should be triggered
 */
export function shouldTriggerMilestone(
  milestone: CelebrationMilestone,
  currentValue: number,
  previousValue: number
): boolean {
  switch (milestone) {
    case 'first_100_messages':
      return previousValue < 100 && currentValue >= 100;
    case 'first_resolved':
      return previousValue < 1 && currentValue >= 1;
    case 'first_workflow':
      return previousValue < 1 && currentValue >= 1;
    default:
      return false;
  }
}

/**
 * Get milestone metadata
 */
export function getMilestoneMetadata(
  milestone: CelebrationMilestone
): { title: string; description: string } {
  const metadata: Record<CelebrationMilestone, { title: string; description: string }> = {
    first_100_messages: {
      title: '🎉 100 Messages!',
      description: 'You have reached 100 messages. Great progress!',
    },
    first_resolved: {
      title: '🎉 First Resolved!',
      description: 'You have resolved your first conversation. Excellent work!',
    },
    first_workflow: {
      title: '🎉 First Workflow!',
      description: 'You have created your first workflow. Automation unlocked!',
    },
  };

  return metadata[milestone];
}
